-- milion_bot database dump 2026-03-18T03:55:20Z

CREATE TABLE scans (
  id                 INTEGER PRIMARY KEY AUTOINCREMENT,
  condition_id       TEXT    NOT NULL,
  market_question    TEXT,
  timestamp          TEXT    NOT NULL,
  end_date           TEXT,
  btc_price          REAL,
  yes_price          REAL,
  no_price           REAL,
  liquidity          REAL,
  claude_probability REAL,
  claude_edge        REAL,
  claude_confidence  REAL,
  recommendation     TEXT,
  reasoning          TEXT,
  action_taken       INTEGER NOT NULL DEFAULT 0,
  resolved           INTEGER NOT NULL DEFAULT 0,
  outcome            TEXT
);
CREATE TABLE sqlite_sequence(name,seq);
CREATE TABLE trades (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  condition_id    TEXT    NOT NULL,
  timestamp       TEXT    NOT NULL,
  recommendation  TEXT,
  probability     REAL,
  edge            REAL,
  confidence      REAL,
  yes_price       REAL,
  size_usdc       REAL,
  order_id        TEXT,
  order_status    TEXT,
  result          TEXT,
  pnl_usdc        REAL
);

